import{_ as a,c as o,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Лицензия: Условия BSL | Plannotator","description":"Изучите условия лицензии Business Source License 1.1 (BSL) для Plannotator и ограничения коммерческого использования. Узнайте о разрешенных сценариях использования, планах будущих изменений и графике перехода на Apache 2.0 в 2030 году.","frontmatter":{"title":"Лицензия: Условия BSL | Plannotator","sidebarTitle":"Понимание правил коммерческого использования","subtitle":"Лицензия: Условия BSL","description":"Изучите условия лицензии Business Source License 1.1 (BSL) для Plannotator и ограничения коммерческого использования. Узнайте о разрешенных сценариях использования, планах будущих изменений и графике перехода на Apache 2.0 в 2030 году.","tags":["Лицензия","BSL-1.1","Коммерческое использование"],"prerequisite":[],"order":3},"headers":[],"relativePath":"ru/backnotprop/plannotator/appendix/license/index.md","filePath":"ru/backnotprop/plannotator/appendix/license/index.md"}'),n={name:"ru/backnotprop/plannotator/appendix/license/index.md"};function e(i,t,s,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="информация-о-лицензии-plannotator" tabindex="-1">Информация о лицензии Plannotator <a class="header-anchor" href="#информация-о-лицензии-plannotator" aria-label="Permalink to &quot;Информация о лицензии Plannotator&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-обучения" tabindex="-1">Что вы сможете сделать после обучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-обучения" aria-label="Permalink to &quot;Что вы сможете сделать после обучения&quot;">​</a></h2><ul><li>Понять тип лицензии и основные условия, используемые Plannotator</li><li>Определить, какие сценарии использования разрешены, а какие ограничены</li><li>Узнать график будущих изменений лицензии</li><li>Понять, как получить коммерческую лицензию или связаться с лицензиаром</li></ul><h2 id="что-вам-нужно-знать-сеичас" tabindex="-1">Что вам нужно знать сейчас <a class="header-anchor" href="#что-вам-нужно-знать-сеичас" aria-label="Permalink to &quot;Что вам нужно знать сейчас&quot;">​</a></h2><p>Plannotator использует <strong>Business Source License 1.1 (BSL)</strong> в качестве лицензии с открытым исходным кодом. Это специальная лицензия, разработанная для защиты коммерческой ценности при одновременном обеспечении полной открытости проекта в будущем.</p><h2 id="основные-условия" tabindex="-1">Основные условия <a class="header-anchor" href="#основные-условия" aria-label="Permalink to &quot;Основные условия&quot;">​</a></h2><h3 id="тип-лицензии" tabindex="-1">Тип лицензии <a class="header-anchor" href="#тип-лицензии" aria-label="Permalink to &quot;Тип лицензии&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Пункт</th><th>Содержание</th></tr></thead><tbody><tr><td><strong>Название лицензии</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>Правообладатель</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>Лицензируемый проект</strong></td><td>plannotator</td></tr><tr><td><strong>Дата изменения</strong></td><td>2030-01-01</td></tr><tr><td><strong>Лицензия после изменения</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Что такое BSL?</p><p>Business Source License — это специальная лицензия, разработанная MariaDB. Она ограничивает определенные коммерческие виды использования в краткосрочной перспективе, но обещает преобразовать программное обеспечение в полностью открытую лицензию (например, Apache 2.0) после определенной даты. Эта модель позволяет проектам с открытым исходным кодом получать устойчивый доход в процессе коммерциализации, обеспечивая при этом долгосрочную открытость для сообщества.</p></div><h3 id="разрешенные-способы-использования" tabindex="-1">Разрешенные способы использования <a class="header-anchor" href="#разрешенные-способы-использования" aria-label="Permalink to &quot;Разрешенные способы использования&quot;">​</a></h3><p>Согласно условиям BSL 1.1, вы можете:</p><ul><li><p>✅ <strong>Копировать, изменять и создавать производные работы</strong></p><ul><li>Вы можете разрабатывать вторичные продукты на основе Plannotator</li><li>Можете изменять исходный код для адаптации к вашим потребностям</li></ul></li><li><p>✅ <strong>Распространять</strong></p><ul><li>Можете распространять оригинальные или измененные версии</li><li>Необходимо сохранять оригинальное уведомление о лицензии</li></ul></li><li><p>✅ <strong>Использование в непроизводственной среде</strong></p><ul><li>Внутренняя разработка, тестирование и оценка</li><li>Личное обучение и исследования</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Широкое использование для личных и корпоративных целей</p><p>BSL имеет широкое определение &quot;использования в непроизводственной среде&quot;, включая различные сценарии для личного и внутрикорпоративного использования. Вы и члены вашей команды (включая независимых подрядчиков) можете свободно использовать Plannotator для разработки, тестирования и развертывания.</p></div><h3 id="ограничения-использования-важно" tabindex="-1">Ограничения использования (важно!) <a class="header-anchor" href="#ограничения-использования-важно" aria-label="Permalink to &quot;Ограничения использования (важно!)&quot;">​</a></h3><p><strong>Основное ограничение</strong>: Plannotator не может использоваться для <strong>сервисов планирования, контекста или утверждения (Planning, Context, or Approval Service)</strong>.</p><h4 id="что-такое-сервис-планирования-контекста-или-утверждения" tabindex="-1">Что такое &quot;сервис планирования, контекста или утверждения&quot;? <a class="header-anchor" href="#что-такое-сервис-планирования-контекста-или-утверждения" aria-label="Permalink to &quot;Что такое &quot;сервис планирования, контекста или утверждения&quot;?&quot;">​</a></h4><p>Любой коммерческий продукт, который позволяет <strong>третьим лицам</strong> (кроме сотрудников и независимых подрядчиков) получать доступ к функциям Plannotator через прямые или косвенные операции, считается ограниченным сервисом. В частности, включая, но не ограничиваясь:</p><ul><li><p><strong>Поставщики облачных услуг</strong></p><ul><li>SaaS-платформы, предоставляющие функции Plannotator как часть своих услуг</li><li>Поставщики хостинговых услуг, предоставляющие Plannotator клиентам или подписчикам</li></ul></li><li><p><strong>Инфраструктурные услуги</strong></p><ul><li>Поставщики услуг центров обработки данных</li><li>Поставщики облачных вычислительных платформ</li></ul></li><li><p><strong>Третьи лица, предоставляющие аналогичные услуги</strong></p><ul><li>Включая любые услуги, предоставляемые вышеуказанными организациями и их аффилированными компаниями</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Предупреждение о коммерческом использовании</p><p>Если вы планируете предоставлять Plannotator как часть коммерческой услуги для использования третьими лицами, вы должны заранее получить коммерческую лицензию. Нарушение этого условия автоматически прекратит ваше право использования текущей и всех версий Plannotator.</p></div><h2 id="график-изменения-лицензии" tabindex="-1">График изменения лицензии <a class="header-anchor" href="#график-изменения-лицензии" aria-label="Permalink to &quot;График изменения лицензии&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Временная точка</th><th>Тип лицензии</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Текущая - 2030-01-01</strong></td><td>BSL 1.1</td><td>Ограниченная лицензия с открытым исходным кодом</td></tr><tr><td><strong>С 2030-01-01</strong></td><td>Apache 2.0</td><td>Полностью открытый исходный код, без коммерческих ограничений</td></tr></tbody></table><h3 id="что-произоидет-после-изменения" tabindex="-1">Что произойдет после изменения? <a class="header-anchor" href="#что-произоидет-после-изменения" aria-label="Permalink to &quot;Что произойдет после изменения?&quot;">​</a></h3><p>С 1 января 2030 года Plannotator автоматически преобразуется в <strong>Apache License 2.0</strong>. Это означает:</p><ul><li>✅ Все коммерческие ограничения будут сняты</li><li>✅ Можно свободно использовать для любых коммерческих целей</li><li>✅ Можно интегрировать в любые SaaS-сервисы</li><li>✅ Соответствует стандартам разрешительных лицензий с открытым исходным кодом</li></ul><h2 id="коммерческая-лицензия" tabindex="-1">Коммерческая лицензия <a class="header-anchor" href="#коммерческая-лицензия" aria-label="Permalink to &quot;Коммерческая лицензия&quot;">​</a></h2><p>Если вам необходимо использовать Plannotator без соблюдения ограничений BSL (например, для сервисов планирования, контекста или утверждения), вы можете:</p><ol><li><p><strong>Приобрести коммерческую лицензию</strong></p><ul><li>Приобрести у backnotprop или его авторизованных дистрибьюторов</li><li>Получить право использования без ограничений BSL</li></ul></li><li><p><strong>Связаться с лицензиаром</strong></p><ul><li>Отправить электронное письмо: backnotprop</li><li>Описать ваш сценарий использования и потребности</li></ul></li></ol><h2 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h2><h3 id="могу-ли-я-использовать-plannotator-внутри-компании" tabindex="-1">Могу ли я использовать Plannotator внутри компании? <a class="header-anchor" href="#могу-ли-я-использовать-plannotator-внутри-компании" aria-label="Permalink to &quot;Могу ли я использовать Plannotator внутри компании?&quot;">​</a></h3><p><strong>Да.</strong> BSL явно разрешает вам и вашим сотрудникам, независимым подрядчикам использовать Plannotator для внутренней разработки, тестирования и развертывания. Ограничение применяется только к сценариям предоставления услуг <strong>третьим лицам</strong> (не сотрудникам и подрядчикам).</p><h3 id="могу-ли-я-разработать-собственныи-продукт-на-основе-plannotator" tabindex="-1">Могу ли я разработать собственный продукт на основе Plannotator? <a class="header-anchor" href="#могу-ли-я-разработать-собственныи-продукт-на-основе-plannotator" aria-label="Permalink to &quot;Могу ли я разработать собственный продукт на основе Plannotator?&quot;">​</a></h3><p><strong>Да, но с условиями.</strong> Если ваш продукт:</p><ul><li>Внутренний инструмент: ✅ Разрешено</li><li>Личный проект: ✅ Разрешено</li><li>Проект с открытым исходным кодом: ✅ Разрешено (сохраните лицензию BSL)</li><li>Коммерческий продукт: ❓ Необходимо оценить, относится ли он к &quot;сервису планирования, контекста или утверждения&quot;</li></ul><h3 id="моя-компания-является-поставщиком-saas-могу-ли-я-использовать" tabindex="-1">Моя компания является поставщиком SaaS, могу ли я использовать? <a class="header-anchor" href="#моя-компания-является-поставщиком-saas-могу-ли-я-использовать" aria-label="Permalink to &quot;Моя компания является поставщиком SaaS, могу ли я использовать?&quot;">​</a></h3><p><strong>Требуется коммерческая лицензия.</strong> Если ваш SaaS-продукт предоставляет функции Plannotator клиентам (даже как часть функциональности), это относится к ограниченным коммерческим услугам, и необходимо приобрести коммерческую лицензию.</p><h3 id="могу-ли-я-использовать-plannotator-для-любых-целеи-после-2030-года" tabindex="-1">Могу ли я использовать Plannotator для любых целей после 2030 года? <a class="header-anchor" href="#могу-ли-я-использовать-plannotator-для-любых-целеи-после-2030-года" aria-label="Permalink to &quot;Могу ли я использовать Plannotator для любых целей после 2030 года?&quot;">​</a></h3><p><strong>Да.</strong> С даты изменения Plannotator будет использовать лицензию Apache 2.0, все коммерческие ограничения будут сняты, и вы сможете свободно использовать его для любых целей.</p><h2 id="полныи-текст-лицензии" tabindex="-1">Полный текст лицензии <a class="header-anchor" href="#полныи-текст-лицензии" aria-label="Permalink to &quot;Полный текст лицензии&quot;">​</a></h2><p>Полный текст Business Source License 1.1 см. в файле <code>LICENSE</code> в корневом каталоге проекта.</p><h2 id="контактная-информация" tabindex="-1">Контактная информация <a class="header-anchor" href="#контактная-информация" aria-label="Permalink to &quot;Контактная информация&quot;">​</a></h2><p>Для получения коммерческой лицензии или по другим вопросам обращайтесь:</p><ul><li><strong>Лицензиар</strong>: backnotprop</li><li><strong>Репозиторий проекта</strong>: <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы рассмотрим <strong><a href="./../../changelog/release-notes/">Журнал изменений</a></strong>.</p><p>Вы увидите:</p><ul><li>История версий Plannotator</li><li>Новые функции и улучшения в каждой версии</li><li>Важные исправления ошибок</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и просмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Уведомление о лицензии</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>Полный текст лицензии</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>Ключевая информация</strong>:</p><ul><li>Тип лицензии: Business Source License 1.1 (BSL)</li><li>Правообладатель: backnotprop (c) 2025</li><li>Дата изменения: 2030-01-01</li><li>Лицензия после изменения: Apache License, Version 2.0</li><li>Основное ограничение: Не может использоваться для сервисов планирования, контекста или утверждения</li></ul></details>',47)])])}const b=a(n,[["render",e]]);export{u as __pageData,b as default};
